// Build repo watchlist — edit repos and registries below
// Scalar config (token, channels, alerts) lives in "Configure Watcher" node
const config = $('Configure Watcher').first().json;

// === GITHUB REPOS ===
const repos = [
  { owner: 'immich-app', repo: 'immich', label: 'Immich', category: 'media', source: 'github', dependsOn: ['postgres', 'redis'] },
  { owner: 'jellyfin', repo: 'jellyfin', label: 'Jellyfin', category: 'media', source: 'github', dependsOn: [] },
  { owner: 'dani-garcia', repo: 'vaultwarden', label: 'Vaultwarden', category: 'security', source: 'github', dependsOn: [] },
  { owner: 'traefik', repo: 'traefik', label: 'Traefik', category: 'networking', source: 'github', dependsOn: [] },
  { owner: 'louislam', repo: 'uptime-kuma', label: 'Uptime Kuma', category: 'monitoring', source: 'github', dependsOn: [] },
  { owner: 'n8n-io', repo: 'n8n', label: 'n8n', category: 'automation', source: 'github', dependsOn: ['postgres', 'redis'] },
  { owner: 'containrrr', repo: 'watchtower', label: 'Watchtower', category: 'management', source: 'github', dependsOn: [] },
  { owner: 'nextcloud', repo: 'server', label: 'Nextcloud', category: 'productivity', source: 'github', dependsOn: ['postgres', 'redis'] },
  { owner: 'grafana', repo: 'grafana', label: 'Grafana', category: 'monitoring', source: 'github', dependsOn: [] },
  { owner: 'prometheus', repo: 'prometheus', label: 'Prometheus', category: 'monitoring', source: 'github', dependsOn: [] },
];

// === CONTAINER REGISTRIES (Docker Hub / GHCR) ===
const registries = [
  { registry: 'dockerhub', namespace: 'linuxserver', image: 'heimdall', label: 'Heimdall (Docker)', category: 'management', source: 'dockerhub', dependsOn: [] },
  { registry: 'dockerhub', namespace: 'linuxserver', image: 'wireguard', label: 'WireGuard (Docker)', category: 'networking', source: 'dockerhub', dependsOn: [] },
];

// === ALERT OVERRIDES (per-repo) ===
// Default alert rules come from Configure Watcher node
var defaultChannels = config.default_channels ? config.default_channels.split(',').map(function(c) { return c.trim(); }) : ['discord'];
var defaultAlertRules = {
  urgencyOverride: null,
  channels: defaultChannels,
  instantAlert: config.default_instant_alert === true
};

var alertOverrides = {
  'dani-garcia/vaultwarden': { urgencyOverride: null, channels: ['discord', 'telegram', 'ntfy'], instantAlert: true },
  'traefik/traefik': { urgencyOverride: null, channels: ['discord', 'telegram'], instantAlert: true },
};

// Build output items
var ghItems = repos.map(function(r) {
  return {
    json: {
      owner: r.owner, repo: r.repo, label: r.label,
      category: r.category, source: r.source, dependsOn: r.dependsOn,
      _githubToken: config.github_token || '',
      alertRules: alertOverrides[r.owner + '/' + r.repo] || defaultAlertRules,
    }
  };
});

var regItems = registries.map(function(r) {
  var repoKey = r.registry + ':' + r.namespace + '/' + r.image;
  var fetchUrl, fetchHeaders;
  if (r.registry === 'dockerhub') {
    fetchUrl = 'https://hub.docker.com/v2/repositories/' + r.namespace + '/' + r.image + '/tags?page_size=5&ordering=last_updated';
    fetchHeaders = {};
  } else if (r.registry === 'ghcr') {
    fetchUrl = 'https://ghcr.io/v2/' + r.namespace + '/' + r.image + '/tags/list';
    fetchHeaders = {};
  }
  return {
    json: {
      owner: r.namespace, repo: r.image, label: r.label,
      category: r.category, source: r.source, registry: r.registry,
      namespace: r.namespace, image: r.image,
      repoKey: repoKey, fetchUrl: fetchUrl, fetchHeaders: fetchHeaders,
      dependsOn: r.dependsOn,
      alertRules: alertOverrides[repoKey] || defaultAlertRules,
    }
  };
});

return [...ghItems, ...regItems];

const repos = $('Deduplicate Watchlist').all().filter(function(i) { return i.json.source === 'github'; });
const responses = $input.all();
const results = [];
let rateLimited = false;

for (let i = 0; i < repos.length; i++) {
  const repo = repos[i].json;
  const res = responses[i] ? responses[i].json : {};

  if (res.message && res.message.includes('rate limit')) {
    rateLimited = true;
    continue;
  }

  if (!res.tag_name) continue;
  if (res.prerelease === true) continue;

  results.push({
    json: {
      owner: repo.owner,
      repo: repo.repo,
      label: repo.label,
      category: repo.category,
      source: 'github',
      tagName: res.tag_name,
      releaseName: res.name || res.tag_name,
      publishedAt: res.published_at,
      htmlUrl: res.html_url,
      changelog: res.body || 'No release notes provided.',
      alertRules: repo.alertRules,
      dependsOn: repo.dependsOn || [],
    }
  });
}

if (rateLimited && results.length === 0) {
  return [{ json: { _rateLimited: true, _error: 'GitHub API rate limit exceeded. Add a GitHub token to the Repo Watchlist node for 5,000 requests/hour.' } }];
}

if (results.length === 0) {
  return [{ json: { _noReleases: true } }];
}

if (rateLimited) {
  results[0].json._rateLimitWarning = 'Some repos were rate limited. Add a token for reliable monitoring.';
}

return results;

// --- TEST MODE ---
const config = $('Configure Watcher').first().json;
const items = $input.all();
if (config.test_mode === true) {
  const testItems = items.filter(i => !i.json._noReleases && !i.json._rateLimited && !i.json._noRegistryReleases && i.json.tagName);
  if (testItems.length > 0) {
    const d = testItems[0].json;
    const out = Object.assign({}, d);
    out.previousTag = '0.0.0-test';
    out._storageKey = d.source === 'github' ? d.owner + '/' + d.repo : d.source + ':' + d.owner + '/' + d.repo;
    out._testMode = true;
    return [{ json: out }];
  }
}

// --- NORMAL MODE ---
const staticData = $getWorkflowStaticData('global');
const newReleases = [];
const isFirstRun = !staticData.initialized;

function normalizeTag(tag) {
  if (!tag) return '';
  return String(tag).trim().replace(/^v/i, '').toLowerCase();
}

for (const item of items) {
  const d = item.json;
  if (d._noReleases || d._rateLimited || d._noRegistryReleases) continue;

  // Use source-aware key for registry items
  const key = d.source === 'github'
    ? d.owner + '/' + d.repo
    : d.source + ':' + d.owner + '/' + d.repo;
  const currentTag = normalizeTag(d.tagName);
  const storedTag = normalizeTag(staticData[key]);

  if (isFirstRun) {
    staticData[key] = d.tagName;
    continue;
  }

  if (storedTag === currentTag) continue;

  const out = Object.assign({}, d);
  out.previousTag = staticData[key] || null;
  out._storageKey = key;
  newReleases.push({ json: out });
}

if (isFirstRun) {
  staticData.initialized = true;
  const seeded = items.filter(function(i) { return !i.json._noReleases && !i.json._rateLimited && !i.json._noRegistryReleases; }).length;
  return [{ json: { _firstRun: true, reposSeeded: seeded } }];
}

if (newReleases.length === 0) {
  const warn = items.find(function(i) { return i.json._rateLimitWarning; });
  const warnMsg = warn ? warn.json._rateLimitWarning : null;
  return [{ json: { _noUpdates: true, _rateLimitWarning: warnMsg } }];
}

return newReleases;

const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;
  let log = d.changelog || '';

  // Preserve breaking changes section
  let breakingSection = '';
  const bMatch = log.match(/(?:#+\s*)?(?:BREAKING|Breaking Changes?|\u26a0\ufe0f)[\s\S]*?(?=\n#{1,3}\s|\n\n---|\n\n\n|$)/i);
  if (bMatch) {
    breakingSection = '\n\n--- BREAKING CHANGES ---\n' + bMatch[0].trim();
  }

  const maxLen = 1500 - breakingSection.length;
  if (log.length > maxLen) {
    log = log.substring(0, maxLen).trim() + '\n\n[...truncated]';
  }

  if (breakingSection && log.indexOf('BREAKING') === -1) {
    log += breakingSection;
  }

  results.push({ json: { ...d, changelogTruncated: log } });
}

return results;

