const items = $input.all();
const repos = $('Prep Changelog for AI').all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const aiText = items[i].json.text || items[i].json.output || '';
  const repoData = repos[i] ? repos[i].json : {};

  let analysis;
  try {
    const jsonMatch = aiText.match(/\{[\s\S]*\}/);
    analysis = jsonMatch ? JSON.parse(jsonMatch[0]) : null;
  } catch (e) {
    analysis = null;
  }

  if (!analysis) {
    analysis = {
      summary: aiText.substring(0, 200),
      breaking: false,
      breakingDetails: null,
      urgency: 'optional',
      security: false,
      securityDetails: null,
      keyChanges: [],
      migrationNotes: ''
    };
  }

  // If security detected and urgency not already critical, escalate
  if (analysis.security === true && analysis.urgency !== 'critical') {
    analysis.urgency = 'critical';
  }

  results.push({
    json: {
      owner: repoData.owner,
      repo: repoData.repo,
      label: repoData.label,
      category: repoData.category,
      source: repoData.source || 'github',
      tagName: repoData.tagName,
      previousTag: repoData.previousTag || null,
      htmlUrl: repoData.htmlUrl,
      publishedAt: repoData.publishedAt,
      changelog: repoData.changelog || repoData.changelogTruncated || '',
      summary: analysis.summary,
      breaking: analysis.breaking === true,
      breakingDetails: analysis.breakingDetails || null,
      urgency: analysis.urgency || 'optional',
      security: analysis.security === true,
      securityDetails: analysis.securityDetails || null,
      keyChanges: analysis.keyChanges || [],
      migrationNotes: analysis.migrationNotes || '',
      alertRules: repoData.alertRules || { channels: ['discord', 'telegram'], instantAlert: false },
      dependsOn: repoData.dependsOn || [],
      _storageKey: repoData._storageKey || (repoData.owner + '/' + repoData.repo),
    }
  });
}

return results;

const items = $input.all();
const _cfg = $('Configure Watcher').first().json;
const allWatchlist = $('Deduplicate Watchlist').all();
const repoCount = allWatchlist.length;
const now = new Date();
const dateStr = now.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });

const order = { critical: 0, recommended: 1, optional: 2 };
const sorted = [...items].sort(function(a, b) {
  const ao = order[a.json.finalUrgency || a.json.urgency] ?? 2;
  const bo = order[b.json.finalUrgency || b.json.urgency] ?? 2;
  if (ao !== bo) return ao - bo;
  return (a.json.label || '').localeCompare(b.json.label || '');
});

const emoji = { critical: '\ud83d\udd34', recommended: '\ud83d\udfe0', optional: '\ud83d\udd35' };
const lbl = { critical: 'CRITICAL', recommended: 'RECOMMENDED', optional: 'OPTIONAL' };

const dependents = {};
for (const w of allWatchlist) {
  var deps = w.json.dependsOn || [];
  for (var di = 0; di < deps.length; di++) {
    if (!dependents[deps[di]]) dependents[deps[di]] = [];
    dependents[deps[di]].push(w.json.label || w.json.repo);
  }
}

const dockerUpdateMap = {
  'immich-app/immich': 'docker compose pull && docker compose up -d',
  'dani-garcia/vaultwarden': 'docker pull vaultwarden/server:TAG && docker compose up -d',
  'traefik/traefik': 'docker pull traefik:TAG && docker compose up -d',
  'louislam/uptime-kuma': 'docker pull louislam/uptime-kuma:TAG && docker compose up -d',
  'n8n-io/n8n': 'docker pull n8nio/n8n:TAG && docker compose up -d',
  'grafana/grafana': 'docker pull grafana/grafana:TAG && docker compose up -d',
  'containrrr/watchtower': 'docker pull containrrr/watchtower:TAG && docker compose up -d',
};

function getUpdateCommand(d) {
  if (d.source === 'dockerhub') return 'docker pull ' + (d.namespace || d.owner) + '/' + (d.image || d.repo) + ':' + d.tagName + ' && docker compose up -d';
  if (d.source === 'ghcr') return 'docker pull ghcr.io/' + (d.namespace || d.owner) + '/' + (d.image || d.repo) + ':' + d.tagName + ' && docker compose up -d';
  var key = d.owner + '/' + d.repo;
  var cmd = dockerUpdateMap[key];
  if (cmd) return cmd.replace(/TAG/g, d.tagName);
  return '# Check ' + key + ' release notes for upgrade instructions';
}

const counts = { critical: 0, recommended: 0, optional: 0 };
for (var ci = 0; ci < sorted.length; ci++) {
  var urg = sorted[ci].json.finalUrgency || sorted[ci].json.urgency || 'optional';
  counts[urg] = (counts[urg] ?? 0) + 1;
}

var text = '\ud83d\udce6 Stack Update Digest \u2014 ' + dateStr + '\n';
text += repoCount + ' sources checked, ' + sorted.length + ' update' + (sorted.length !== 1 ? 's' : '') + ' found.\n\n';

var slackText = '*\ud83d\udce6 Stack Update Digest* \u2014 ' + dateStr + '\n' + repoCount + ' sources checked, ' + sorted.length + ' updates\n\n';
var embeds = [];

for (var si = 0; si < sorted.length; si++) {
  var d = sorted[si].json;
  var urgency = d.finalUrgency || d.urgency || 'optional';
  var e = emoji[urgency] ?? '\ud83d\udd35';
  var l = lbl[urgency] ?? 'OPTIONAL';
  var sourceTag = d.source !== 'github' ? ' [' + d.source.toUpperCase() + ']' : '';
  var updateCmd = getUpdateCommand(d);

  text += e + ' ' + l + ': ' + d.label + ' ' + d.tagName + sourceTag;
  if (d.previousTag) text += ' (was ' + d.previousTag + ')';
  text += '\n   ' + d.summary + '\n';
  if (d.breaking && d.breakingDetails) text += '   \u26a0\ufe0f BREAKING: ' + d.breakingDetails + '\n';
  if (d.security && d.securityDetails) text += '   \ud83d\udee1\ufe0f SECURITY: ' + d.securityDetails + '\n';
  if (d.keyChanges && d.keyChanges.length > 0) text += '   Key changes: ' + d.keyChanges.join('; ') + '\n';
  if (d.migrationNotes) text += '   \ud83d\udccb Migration: ' + d.migrationNotes + '\n';
  text += '   \ud83d\udcbb `' + updateCmd + '`\n';
  var repoName = d.repo || d.image;
  if (dependents[repoName] && dependents[repoName].length > 0) {
    text += '   \ud83d\udd17 Heads up: ' + dependents[repoName].join(', ') + ' depend on ' + repoName + '\n';
  }
  text += '   \u2192 ' + d.htmlUrl + '\n\n';

  slackText += e + ' *' + l + ': ' + d.label + ' ' + d.tagName + '*' + sourceTag + '\n';
  slackText += d.summary + '\n';
  if (d.security) slackText += '\ud83d\udee1\ufe0f ' + (d.securityDetails || 'Security update') + '\n';
  slackText += '```' + updateCmd + '```\n<' + d.htmlUrl + '|Release Notes>\n\n';

  var color = urgency === 'critical' ? 16711680 : urgency === 'recommended' ? 16750848 : 3381503;
  var desc = d.summary;
  if (d.breaking) desc += '\n\n\u26a0\ufe0f **BREAKING:** ' + (d.breakingDetails || 'See release notes');
  if (d.security) desc += '\n\n\ud83d\udee1\ufe0f **SECURITY:** ' + (d.securityDetails || 'Security-related');
  if (d.keyChanges && d.keyChanges.length > 0) desc += '\n\n**Key changes:** ' + d.keyChanges.join(', ');
  desc += '\n\n```\n' + updateCmd + '\n```';

  embeds.push({
    title: e + ' ' + d.label + ' ' + d.tagName + sourceTag,
    description: d.previousTag ? desc + '\n\nPrevious: ' + d.previousTag : desc,
    url: d.htmlUrl,
    color: color,
    footer: { text: l + (d.security ? ' | SECURITY' : '') },
  });
}

var parts = [];
if (counts.critical > 0) parts.push(counts.critical + ' critical');
if (counts.recommended > 0) parts.push(counts.recommended + ' recommended');
if (counts.optional > 0) parts.push(counts.optional + ' optional');
text += '\u2014 ' + parts.join(', ') + '.';

return [{
  json: {
    digest: text,
    discordPayload: {
      content: '\ud83d\udce6 **Stack Update Digest** \u2014 ' + dateStr + ' (' + repoCount + ' sources checked)',
      embeds: embeds,
    },
    telegramMessage: text,
    slackText: slackText,
    ntfyPayload: { topic: (_cfg.ntfy_topic || 'release-watcher'), title: 'Stack Update Digest \u2014 ' + dateStr, message: sorted.length + ' updates: ' + parts.join(', '), priority: counts.critical > 0 ? 4 : 3, tags: counts.critical > 0 ? ['package', 'warning'] : ['package'] },
    updateCount: sorted.length,
    urgencyCounts: counts,
    updates: sorted.map(function(s) {
      return { key: s.json._storageKey || (s.json.owner + '/' + s.json.repo), tag: s.json.tagName };
    }),
  }
}];

const staticData = $getWorkflowStaticData('global');
const updates = $input.first().json.updates || [];

for (const u of updates) {
  staticData[u.key] = u.tag;
}

return [{ json: { versionsUpdated: updates.length, versions: updates } }];

const items = $input.all();
const prepItems = $('Prep Changelog for AI').all();
const results = [];

function esc(val) {
  if (val === null || val === undefined || val === '') return 'NULL';
  return "'" + String(val).replace(/'/g, "''") + "'";
}

for (let i = 0; i < items.length; i++) {
  const d = items[i].json;
  const prep = prepItems[i] ? prepItems[i].json : {};

  const repoKey = d.source === 'github'
    ? d.owner + '/' + d.repo
    : d.source + ':' + d.owner + '/' + d.repo;
  const source = d.source || 'github';

  const query = 'INSERT INTO release_history (repo_key, source, tag_name, previous_tag, release_url, changelog_raw, ai_summary, ai_urgency, has_breaking_changes, breaking_details, security_advisory, advisory_severity, update_command) VALUES ('
    + esc(repoKey) + ', '
    + esc(source) + ', '
    + esc(d.tagName) + ', '
    + esc(d.previousTag || null) + ', '
    + esc(d.htmlUrl) + ', '
    + esc(prep.changelog ? prep.changelog.substring(0, 10000) : (d.changelog ? d.changelog.substring(0, 10000) : null)) + ', '
    + esc(d.summary) + ', '
    + esc(d.urgency) + ', '
    + (d.breaking || false) + ', '
    + esc(d.breakingDetails) + ', '
    + (d.security || false) + ', '
    + esc(d.securityDetails ? 'high' : null) + ', '
    + esc(d.updateCommand || null)
    + ') ON CONFLICT DO NOTHING';

  results.push({ json: { _dbQuery: query } });
}

return results;

const watchlist = $('Deduplicate Watchlist').all().filter(function(i) { return i.json.source !== 'github'; });
const responses = $input.all();
const results = [];

for (let i = 0; i < watchlist.length; i++) {
  const reg = watchlist[i].json;
  const res = responses[i] ? responses[i].json : {};

  let tagName = null;
  let publishedAt = null;

  if (reg.registry === 'dockerhub') {
    // Docker Hub returns {results: [{name, last_updated, ...}]}
    const tags = res.results || [];
    // Find first non-latest stable tag
    const stable = tags.find(function(t) {
      return t.name !== 'latest' && !t.name.includes('-rc') && !t.name.includes('-beta') && !t.name.includes('-alpha');
    });
    if (stable) {
      tagName = stable.name;
      publishedAt = stable.last_updated || stable.tag_last_pushed;
    }
  } else if (reg.registry === 'ghcr') {
    // GHCR returns {name, tags: ['v1.0', 'latest', ...]}
    const tags = res.tags || [];
    const stable = tags.filter(function(t) {
      return t !== 'latest' && !t.includes('-rc') && !t.includes('-beta');
    }).sort().reverse();
    if (stable.length > 0) tagName = stable[0];
  }

  if (!tagName) continue;

  results.push({
    json: {
      owner: reg.namespace,
      repo: reg.image,
      label: reg.label,
      category: reg.category,
      source: reg.source,
      registry: reg.registry,
      namespace: reg.namespace,
      image: reg.image,
      tagName: tagName,
      releaseName: tagName,
      publishedAt: publishedAt,
      htmlUrl: reg.registry === 'dockerhub'
        ? 'https://hub.docker.com/r/' + reg.namespace + '/' + reg.image
        : 'https://ghcr.io/' + reg.namespace + '/' + reg.image,
      changelog: 'Container image tag update. Check source repo for release notes.',
      alertRules: reg.alertRules,
      dependsOn: reg.dependsOn || [],
    }
  });
}

if (results.length === 0) {
  return [{ json: { _noRegistryReleases: true } }];
}

return results;

const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;
  const rules = d.alertRules || { channels: ['discord', 'telegram'], instantAlert: false, urgencyOverride: null };

  const finalUrgency = rules.urgencyOverride || d.urgency || 'optional';
  const isInstant = rules.instantAlert === true || finalUrgency === 'critical';
  const channels = rules.channels || ['discord', 'telegram'];

  results.push({
    json: {
      ...d,
      finalUrgency: finalUrgency,
      isInstant: isInstant,
      channels: channels,
    }
  });
}

return results;

// Format individual instant alerts (one per critical/instant-flagged release)
const _cfg = $('Configure Watcher').first().json;
const items = $input.all();
const results = [];

const emoji = { critical: '\ud83d\udd34', recommended: '\ud83d\udfe0', optional: '\ud83d\udd35' };

// Map of update commands
const dockerUpdateMap = {
  'immich-app/immich': 'docker compose pull && docker compose up -d',
  'dani-garcia/vaultwarden': 'docker pull vaultwarden/server:TAG && docker compose up -d',
  'traefik/traefik': 'docker pull traefik:TAG && docker compose up -d',
  'n8n-io/n8n': 'docker pull n8nio/n8n:TAG && docker compose up -d',
};

function getUpdateCommand(d) {
  if (d.source === 'dockerhub') return 'docker pull ' + d.namespace + '/' + d.image + ':' + d.tagName;
  if (d.source === 'ghcr') return 'docker pull ghcr.io/' + d.namespace + '/' + d.image + ':' + d.tagName;
  var key = d.owner + '/' + d.repo;
  var cmd = dockerUpdateMap[key];
  if (cmd) return cmd.replace(/TAG/g, d.tagName);
  return '# Check ' + key + ' release notes';
}

for (const item of items) {
  const d = item.json;
  const e = emoji[d.finalUrgency] || '\ud83d\udd34';
  const sourceTag = d.source !== 'github' ? ' [' + d.source.toUpperCase() + ']' : '';
  const updateCmd = getUpdateCommand(d);

  let text = e + ' URGENT: ' + d.label + ' ' + d.tagName + sourceTag + '\n';
  text += d.summary + '\n';
  if (d.breaking) text += '\u26a0\ufe0f BREAKING: ' + (d.breakingDetails || 'See release notes') + '\n';
  if (d.security) text += '\ud83d\udee1\ufe0f SECURITY: ' + (d.securityDetails || 'Security-related') + '\n';
  if (d.keyChanges && d.keyChanges.length > 0) text += 'Key changes: ' + d.keyChanges.join('; ') + '\n';
  text += '\ud83d\udcbb `' + updateCmd + '`\n';
  text += '\u2192 ' + d.htmlUrl;

  const color = d.finalUrgency === 'critical' ? 16711680 : 16750848;
  results.push({
    json: {
      channels: d.channels,
      digest: text,
      telegramMessage: text,
      discordPayload: {
        content: e + ' **URGENT UPDATE** \u2014 ' + d.label,
